INSERT OR IGNORE INTO templates (key, category, state, message, button_text, button_url, auto_delete, delay_sec) VALUES ('trading_explanation_01', 'trading_explanation', 'brain', 'CALL means you predict price will go up; PUT means down. Expiry is the time when the trade closes—1 minute, 5 minutes, etc. If your prediction is right at expiry, you profit. Simple.', 'Open Demo Account', 'https://iqoption.com/affiliate/demo', 0, 0);
INSERT OR IGNORE INTO templates (key, category, state, message, button_text, button_url, auto_delete, delay_sec) VALUES ('trading_explanation_02', 'trading_explanation', 'brain', 'Binary options are all about yes/no questions: ''Will EUR/USD be higher in 5 minutes?'' If yes, CALL wins. If no, PUT wins. 10x Bot helps you answer correctly more often.', 'Try a Free Signal', 'https://t.me/10xbot/free', 0, 0);
INSERT OR IGNORE INTO templates (key, category, state, message, button_text, button_url, auto_delete, delay_sec) VALUES ('trading_explanation_03', 'trading_explanation', 'brain', '📈 CALL = buy (price up), PUT = sell (price down). Expiry times vary from 60 seconds to 1 hour. The bot picks the best expiry for each setup. You just click and collect.', 'Learn More on IQ', 'https://iqoption.com/affiliate/learn', 0, 0);
INSERT OR IGNORE INTO templates (key, category, state, message, button_text, button_url, auto_delete, delay_sec) VALUES ('trading_explanation_04', 'trading_explanation', 'brain', 'Think of it like a bet on direction. CALL = price will rise, PUT = price will fall. You choose the expiry time, and if you''re right, you get a payout (typically 70-90%).', 'Start Trading', 'https://iqoption.com/affiliate/start', 0, 0);
INSERT OR IGNORE INTO templates (key, category, state, message, button_text, button_url, auto_delete, delay_sec) VALUES ('trading_explanation_05', 'trading_explanation', 'brain', '⏰ Expiry matters! Short expiries (1-5 min) are fast and intense. Longer ones (15-60 min) give more room. The bot''s signals are optimized for each timeframe. Your job? Execute.', 'Check Bot Signals', 'https://t.me/10xbot/signals', 0, 0);
INSERT OR IGNORE INTO templates (key, category, state, message, button_text, button_url, auto_delete, delay_sec) VALUES ('trading_explanation_06', 'trading_explanation', 'brain', 'Binary options trading on IQ Option is straightforward: pick an asset, predict direction, set expiry, invest. If correct, profit. 10x Bot does the analysis—you get the edge.', 'Open IQ Account', 'https://iqoption.com/affiliate/register', 0, 0);
