INSERT OR IGNORE INTO templates (key, category, state, message, button_text, button_url, auto_delete, delay_sec) VALUES ('upgrade_migration_05', 'upgrade_migration', 'brain', 'No problem! 💜 To upgrade from demo, just type `/subscribe pro`. If you''re on PRO and want MASTER, use `/subscribe master`. It''s instant — you''ll get access right away. Need help?', '🎯 Start Upgrade', 'https://t.me/10xbot/upgrade', 0, 0);
