INSERT OR IGNORE INTO templates (key, category, state, message, button_text, button_url, auto_delete, delay_sec) VALUES ('withdrawal_01', 'withdrawal', 'brain', 'Withdrawals are processed via bank transfer or USDT (TRC20/ERC20). Minimum withdrawal is $10. Processing time is 24-48 hours for bank, up to 2 hours for crypto.', '📤 Withdraw Guide', 'https://t.me/10xbot/withdraw', 0, 0);
