INSERT OR IGNORE INTO templates (key, category, state, message, auto_delete, delay_sec) VALUES ('withdrawal_04', 'withdrawal', 'brain', 'To withdraw, go to your IQ Option account, select withdrawal method (bank transfer or USDT), and enter amount (min $10). Crypto is fastest (2 hours), bank takes 1-2 days.', 0, 0);
INSERT OR IGNORE INTO templates (key, category, state, message, button_text, button_url, auto_delete, delay_sec) VALUES ('withdrawal_05', 'withdrawal', 'brain', 'No worries! 💜 Withdrawals are simple. Minimum $10, choose bank or USDT. Crypto is super fast (under 2 hours), bank might take a day or two. I''m here if you need a walkthrough!', '📤 Withdraw Help', 'https://t.me/10xbot/support', 0, 0);
